17→func Handler(db *pgxpool.Pool) http.HandlerFunc {
18→	return func(w http.ResponseWriter, r *http.Request) {
19→		dbOK := false
20→		if db != nil {
21→			ctx, cancel := context.WithTimeout(r.Context(), 500*time.Millisecond)
22→			defer cancel()
23→			if err := db.Ping(ctx); err == nil {
24→				dbOK = true
