 1→package httpx
 2→
 3→import (
 4→	"net/http"
 5→	"strings"
 6→
 7→	"github.com/paretoimproved/local-roots/backend/internal/config"
 8→)
 9→
10→func withCORS(cfg config.Config, next http.Handler) http.Handler {
11→	allowed := parseAllowedOrigins(cfg.CORSAllowOrigins)
12→
13→	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
14→		origin := r.Header.Get("Origin")
15→		if origin != "" && isOriginAllowed(cfg, origin, allowed) {
16→			w.Header().Set("Access-Control-Allow-Origin", origin)
17→			w.Header().Set("Vary", "Origin")
18→			w.Header().Set("Access-Control-Allow-Credentials", "true")
19→			w.Header().Set("Access-Control-Allow-Methods", "GET,POST,PATCH,DELETE,OPTIONS")
20→			w.Header().Set("Access-Control-Allow-Headers", "Authorization,Content-Type")
21→			w.Header().Set("Access-Control-Max-Age", "600")
22→		}
23→
24→		if r.Method == http.MethodOptions {
25→			w.WriteHeader(http.StatusNoContent)
26→			return
27→		}
28→
29→		next.ServeHTTP(w, r)
30→	})
31→}
32→
33→func parseAllowedOrigins(v string) []string {
34→	var out []string
35→	for _, part := range strings.Split(v, ",") {
36→		s := strings.TrimSpace(part)
37→		if s == "" {
38→			continue
39→		}
40→		out = append(out, s)
41→	}
42→	return out
43→}
44→
45→func isOriginAllowed(cfg config.Config, origin string, allowed []string) bool {
46→	// Explicit allow list wins.
47→	for _, a := range allowed {
48→		if origin == a {
49→			return true
50→		}
51→	}
52→
53→	// In production, require explicit allowlisting to avoid accidentally accepting
54→	// requests from unrelated browser clients.
55→	if cfg.Env == "prod" {
56→		return false
57→	}
58→
59→	// Reasonable default for Vercel previews in non-prod environments.
60→	if strings.HasSuffix(origin, ".vercel.app") && strings.HasPrefix(origin, "https://") {
61→		return true
62→	}
63→
64→	// Local dev.
65→	if origin == "http://localhost:3000" || origin == "http://127.0.0.1:3000" {
66→		return true
67→	}
68→
69→	return false
70→}
