 1→package email
 2→
 3→import (
 4→	"bytes"
 5→	"encoding/json"
 6→	"fmt"
 7→	"io"
 8→	"log"
 9→	"net/http"
10→	"time"
11→)
12→
13→var httpClient = &http.Client{Timeout: 10 * time.Second}
14→
15→type Client struct {
16→	apiKey string
17→	from   string
18→}
19→
20→func New(apiKey string, from string) *Client {
21→	if apiKey == "" {
22→		return nil
23→	}
24→	return &Client{apiKey: apiKey, from: from}
25→}
26→
27→func (c *Client) Enabled() bool { return c != nil && c.apiKey != "" }
28→
29→type sendRequest struct {
30→	From    string   `json:"from"`
31→	To      []string `json:"to"`
32→	Subject string   `json:"subject"`
33→	Text    string   `json:"text"`
34→}
35→
36→// Send sends a plain-text email via Resend. Fire-and-forget safe.
37→func (c *Client) Send(to string, subject string, body string) error {
38→	if !c.Enabled() {
39→		return nil
40→	}
41→
42→	payload, err := json.Marshal(sendRequest{
43→		From:    c.from,
44→		To:      []string{to},
45→		Subject: subject,
46→		Text:    body,
47→	})
48→	if err != nil {
49→		return err
50→	}
51→
52→	req, err := http.NewRequest("POST", "https://api.resend.com/emails", bytes.NewReader(payload))
53→	if err != nil {
54→		return err
55→	}
56→	req.Header.Set("Authorization", "Bearer "+c.apiKey)
57→	req.Header.Set("Content-Type", "application/json")
58→
59→	resp, err := httpClient.Do(req)
60→	if err != nil {
61→		return err
62→	}
63→	defer resp.Body.Close()
64→
65→	if resp.StatusCode >= 400 {
66→		body, _ := io.ReadAll(io.LimitReader(resp.Body, 1024))
67→		return fmt.Errorf("resend: %d %s", resp.StatusCode, string(body))
68→	}
69→	return nil
70→}
71→
72→// SendAsync sends an email in a goroutine. Errors are logged, not returned.
73→func (c *Client) SendAsync(to string, subject string, body string) {
74→	if !c.Enabled() {
75→		return
76→	}
77→	go func() {
78→		if err := c.Send(to, subject, body); err != nil {
79→			log.Printf("email send error to=%s subject=%q: %v", to, subject, err)
80→		}
81→	}()
82→}
