 22→      title,
 23→      description,
 24→      openGraph: {
 25→        title,
 26→        description,
 27→        type: "website",
 28→        images: [`/stores/${storeId}/opengraph-image`],
 29→      },
 30→    };
 31→  } catch {
 32→    return { title: "Farm — Local Roots" };
 33→  }
