  1→package scheduler
  2→
  3→import (
  4→	"context"
  5→	"log"
  6→	"time"
  7→
  8→	"github.com/jackc/pgx/v5/pgxpool"
  9→
 10→	v1 "github.com/paretoimproved/local-roots/backend/internal/api/v1"
 11→	"github.com/paretoimproved/local-roots/backend/internal/email"
 12→	"github.com/paretoimproved/local-roots/backend/internal/payments/stripepay"
 13→)
 14→
 15→// Start launches in-process cron jobs. It blocks until ctx is cancelled.
 16→// Call this in a goroutine from main.go.
 17→//
 18→// Jobs:
 19→//   - Billing authorization: every 30 minutes
 20→//   - Pickup reminders: every 30 minutes (offset by 15 min)
 21→//   - Re-engagement emails: every 6 hours
 22→//   - Review prompts: every 30 minutes
 23→//   - Transfer retry: every hour
 24→//   - Milestone emails: every 6 hours
 25→//   - Seller weekly digest: every hour (sends only on Monday 14:00 UTC)
 26→func Start(ctx context.Context, db *pgxpool.Pool, stripeClient *stripepay.Client, emailClient *email.Client, frontendURL string) {
 27→	billingTicker := time.NewTicker(30 * time.Minute)
 28→	reminderTicker := time.NewTicker(30 * time.Minute)
 29→	reengagementTicker := time.NewTicker(6 * time.Hour)
 30→	reviewPromptTicker := time.NewTicker(30 * time.Minute)
 31→	transferRetryTicker := time.NewTicker(1 * time.Hour)
 32→	milestoneTicker := time.NewTicker(6 * time.Hour)
 33→	digestTicker := time.NewTicker(1 * time.Hour)
 34→	defer billingTicker.Stop()
 35→	defer reminderTicker.Stop()
 36→	defer reengagementTicker.Stop()
 37→	defer reviewPromptTicker.Stop()
 38→	defer transferRetryTicker.Stop()
 39→	defer milestoneTicker.Stop()
 40→	defer digestTicker.Stop()
 41→
 42→	log.Printf("scheduler: started (billing=30m, reminders=30m, reengagement=6h, review_prompts=30m, transfer_retry=1h, milestones=6h, digest=1h)")
 43→
 44→	// Run billing immediately on startup, then on tick.
 45→	go runBilling(ctx, db, stripeClient)
 46→
 47→	// Delay reminders by 15 min to stagger with billing.
 48→	go func() {
 49→		select {
 50→		case <-time.After(15 * time.Minute):
 51→			runReminders(ctx, db, emailClient, frontendURL)
 52→		case <-ctx.Done():
 53→		}
 54→	}()
 55→
 56→	for {
 57→		select {
 58→		case <-ctx.Done():
 59→			log.Printf("scheduler: stopped")
 60→			return
 61→		case <-billingTicker.C:
 62→			go runBilling(ctx, db, stripeClient)
 63→		case <-reminderTicker.C:
 64→			go runReminders(ctx, db, emailClient, frontendURL)
 65→		case <-reengagementTicker.C:
 66→			go runReengagement(ctx, db, emailClient, frontendURL)
 67→		case <-reviewPromptTicker.C:
 68→			go runReviewPrompts(ctx, db, emailClient, frontendURL)
 69→		case <-transferRetryTicker.C:
 70→			go runTransferRetry(ctx, db, stripeClient)
 71→		case <-milestoneTicker.C:
 72→			go runMilestones(ctx, db, emailClient)
 73→		case <-digestTicker.C:
 74→			go runDigest(ctx, db, emailClient)
 75→		}
 76→	}
 77→}
 78→
 79→func runBilling(ctx context.Context, db *pgxpool.Pool, stripeClient *stripepay.Client) {
 80→	defer func() {
 81→		if r := recover(); r != nil {
 82→			log.Printf("scheduler: billing panic: %v", r)
 83→		}
 84→	}()
 85→
 86→	if db == nil || stripeClient == nil || !stripeClient.Enabled() {
 87→		return
 88→	}
 89→
 90→	result, err := v1.RunBillingAuthorization(ctx, db, stripeClient)
 91→	if err != nil {
 92→		log.Printf("scheduler: billing error: %v", err)
 93→		return
 94→	}
 95→	log.Printf("scheduler: billing candidates=%d authorized=%d failed=%d until=%s",
 96→		result.Candidates, result.Authorized, result.Failed, result.Until.Format(time.RFC3339))
 97→}
 98→
 99→func runReminders(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client, frontendURL string) {
100→	defer func() {
101→		if r := recover(); r != nil {
102→			log.Printf("scheduler: reminders panic: %v", r)
103→		}
104→	}()
105→
106→	if db == nil || emailClient == nil || !emailClient.Enabled() {
107→		return
108→	}
109→
110→	result, err := v1.RunPickupReminders(ctx, db, emailClient, frontendURL)
111→	if err != nil {
112→		log.Printf("scheduler: reminders error: %v", err)
113→		return
114→	}
115→	log.Printf("scheduler: reminders candidates=%d sent=%d",
116→		result.Candidates, result.Sent)
117→}
118→
119→func runReengagement(ctx context.Context, db *pgxpool.Pool, emailClient *email.Client, frontendURL string) {
120→	defer func() {
121→		if r := recover(); r != nil {
122→			log.Printf("scheduler: reengagement panic: %v", r)
123→		}
124→	}()
125→
126→	if db == nil || emailClient == nil || !emailClient.Enabled() {
127→		return
