  3→import (
  4→	"bytes"
  5→	"context"
  6→	"encoding/json"
  7→	"io"
  8→	"net/http"
  9→	"strings"
 10→
 11→	"github.com/jackc/pgx/v5"
 12→	"github.com/jackc/pgx/v5/pgxpool"
 13→	stripe "github.com/stripe/stripe-go/v78"
 14→	"github.com/stripe/stripe-go/v78/webhook"
 15→
 16→	"github.com/paretoimproved/local-roots/backend/internal/resp"
 17→)
 18→
 19→type StripeWebhookAPI struct {
 20→	DB            *pgxpool.Pool
 21→	WebhookSecret string
 22→}
 23→
 24→// StripeWebhook handles asynchronous payment state updates.
 25→// For MVP we keep this minimal:
 26→// - synchronize orders.payment_status from Stripe PaymentIntent events
 27→// - if a payment fails/cancels while the order is still "placed", cancel it and release inventory
 28→func (a StripeWebhookAPI) StripeWebhook(w http.ResponseWriter, r *http.Request) {
 29→	secrets := splitWebhookSecrets(a.WebhookSecret)
 30→	if len(secrets) == 0 {
 31→		resp.ServiceUnavailable(w, "webhook not configured")
 32→		return
 33→	}
 34→	if a.DB == nil {
 35→		resp.ServiceUnavailable(w, "database not configured")
 36→		return
 37→	}
 38→	if r.Method != http.MethodPost {
 39→		resp.BadRequest(w, "invalid method")
 40→		return
 41→	}
 42→
 43→	body, err := io.ReadAll(io.LimitReader(r.Body, 2<<20))
 44→	if err != nil {
 45→		resp.BadRequest(w, "invalid body")
 46→		return
 47→	}
 48→	// Restore body (useful for debugging on error paths).
 49→	r.Body = io.NopCloser(bytes.NewReader(body))
 50→
 51→	sig := r.Header.Get("Stripe-Signature")
 52→	ev, err := constructStripeEvent(body, sig, secrets)
 53→	if err != nil {
 54→		resp.BadRequest(w, "invalid signature")
 55→		return
 56→	}
 57→
 58→	ctx := r.Context()
 59→
 60→	switch ev.Type {
 61→	case "payment_intent.requires_capture":
 62→		var pi stripe.PaymentIntent
 63→		if err := json.Unmarshal(ev.Data.Raw, &pi); err == nil && pi.ID != "" {
 64→			zero := 0
 65→			if err := a.updatePaymentByPI(ctx, pi.ID, "authorized", &zero, false); err != nil {
 66→				resp.Internal(w, err)
 67→				return
 68→			}
 69→		}
 70→	case "payment_intent.succeeded":
 71→		var pi stripe.PaymentIntent
 72→		if err := json.Unmarshal(ev.Data.Raw, &pi); err == nil && pi.ID != "" {
 73→			amt := int(pi.AmountReceived)
 74→			if err := a.updatePaymentByPI(ctx, pi.ID, "paid", &amt, false); err != nil {
 75→				resp.Internal(w, err)
 76→				return
 77→			}
 78→		}
 79→	case "payment_intent.canceled":
 80→		var pi stripe.PaymentIntent
 81→		if err := json.Unmarshal(ev.Data.Raw, &pi); err == nil && pi.ID != "" {
 82→			zero := 0
 83→			if err := a.updatePaymentByPI(ctx, pi.ID, "voided", &zero, true); err != nil {
 84→				resp.Internal(w, err)
 85→				return
 86→			}
 87→		}
 88→	case "payment_intent.payment_failed":
 89→		var pi stripe.PaymentIntent
 90→		if err := json.Unmarshal(ev.Data.Raw, &pi); err == nil && pi.ID != "" {
 91→			zero := 0
 92→			if err := a.updatePaymentByPI(ctx, pi.ID, "failed", &zero, true); err != nil {
 93→				resp.Internal(w, err)
 94→				return
 95→			}
 96→		}
 97→	case "account.updated":
 98→		var acct stripe.Account
 99→		if err := json.Unmarshal(ev.Data.Raw, &acct); err == nil && acct.ID != "" {
100→			status := "onboarding"
101→			if acct.ChargesEnabled && acct.PayoutsEnabled {
102→				status = "active"
103→			} else if acct.Requirements != nil && len(acct.Requirements.Errors) > 0 {
104→				status = "restricted"
105→			} else if acct.ChargesEnabled || acct.PayoutsEnabled {
106→				status = "restricted"
107→			}
108→			if _, err := a.DB.Exec(ctx, `
109→				update stores
110→				set stripe_account_status = $2, updated_at = now()
111→				where stripe_account_id = $1
112→			`, acct.ID, status); err != nil {
113→				resp.Internal(w, err)
114→				return
115→			}
116→		}
117→	default:
118→		// ignore other events for MVP
119→	}
120→
121→	resp.OK(w, map[string]any{"ok": true})
122→}
123→
124→func splitWebhookSecrets(v string) []string {
125→	// Allow comma/newline-separated secrets to support rotation without downtime.
126→	v = strings.ReplaceAll(v, "\n", ",")
127→	var out []string
128→	for _, part := range strings.Split(v, ",") {
129→		s := strings.TrimSpace(part)
130→		if s == "" {
131→			continue
132→		}
133→		out = append(out, s)
134→	}
135→	return out
136→}
137→
138→func constructStripeEvent(body []byte, sig string, secrets []string) (stripe.Event, error) {
139→	// Try each secret; useful during secret rotation.
140→	var lastErr error
141→	for _, s := range secrets {
142→		ev, err := webhook.ConstructEvent(body, sig, s)
143→		if err == nil {
144→			return ev, nil
145→		}
146→		lastErr = err
147→	}
148→	return stripe.Event{}, lastErr
149→}
150→
151→// validPaymentTransition returns true if moving from → to is a legal
152→// payment_status progression. Backward or no-op transitions are rejected
153→// so that out-of-order or duplicate Stripe webhooks cannot corrupt state.
154→func validPaymentTransition(from, to string) bool {
155→	allowed := map[string]map[string]bool{
156→		"unpaid":          {"authorized": true, "paid": true, "failed": true},
157→		"pending":         {"authorized": true, "paid": true, "failed": true},
158→		"authorized":      {"paid": true, "voided": true, "failed": true},
159→		"requires_action": {"authorized": true, "paid": true, "failed": true, "voided": true},
160→		"failed":          {"authorized": true, "paid": true},
161→	}
162→	m, ok := allowed[from]
163→	if !ok {
164→		return false
165→	}
166→	return m[to]
167→}
168→
169→func (a StripeWebhookAPI) updatePaymentByPI(ctx context.Context, paymentIntentID string, paymentStatus string, capturedCents *int, cancelIfPlaced bool) error {
170→	tx, err := a.DB.Begin(ctx)
171→	if err != nil {
172→		return err
173→	}
174→	defer tx.Rollback(ctx)
175→
176→	var (
177→		orderID              string
178→		storeID              string
179→		status               string
180→		method               string
181→		currentPaymentStatus string
182→	)
183→	err = tx.QueryRow(ctx, `
184→		select id::text, store_id::text, status, payment_method, payment_status
185→		from orders
186→		where stripe_payment_intent_id = $1
187→		limit 1
188→		for update
189→	`, paymentIntentID).Scan(&orderID, &storeID, &status, &method, &currentPaymentStatus)
190→	if err != nil {
191→		if err == pgx.ErrNoRows {
192→			return nil
193→		}
194→		return err
195→	}
196→
197→	// Reject backward or invalid payment state transitions (e.g., paid→authorized).
198→	if !validPaymentTransition(currentPaymentStatus, paymentStatus) {
199→		return nil
200→	}
201→
202→	// Sync payment fields from Stripe; this keeps UI accurate after async changes.
203→	if capturedCents != nil {
204→		if _, err := tx.Exec(ctx, `
205→			update orders
206→			set payment_status = $2,
207→				captured_cents = $3,
208→				updated_at = now()
209→			where id = $1::uuid
210→		`, orderID, paymentStatus, *capturedCents); err != nil {
211→			return err
212→		}
213→	} else {
214→		if _, err := tx.Exec(ctx, `
215→			update orders
216→			set payment_status = $2, updated_at = now()
217→			where id = $1::uuid
218→		`, orderID, paymentStatus); err != nil {
219→			return err
220→		}
221→	}
222→
223→	// If the payment failed/voided before seller fulfillment started, cancel and release inventory.
224→	if cancelIfPlaced && method == "card" && status == "placed" {
225→		if err := adjustOfferingsForOrder(ctx, tx, orderID, "release"); err != nil {
226→			return err
227→		}
228→		if _, err := tx.Exec(ctx, `
229→			update orders
230→			set status = 'canceled', updated_at = now()
231→			where id = $1::uuid
232→		`, orderID); err != nil {
233→			return err
234→		}
235→	}
236→
237→	return tx.Commit(ctx)
238→}
