 38→  const [location, setLocation] = useState<SellerPickupLocation | null>(null);
 39→  const [plan, setPlan] = useState<SellerSubscriptionPlan | null>(null);
 40→  const [launched, setLaunched] = useState(false);
 41→  const [copied, setCopied] = useState(false);
 42→
 43→  useEffect(() => {
 44→    const token = session.getToken();
 45→    if (!token) {
 46→      router.replace("/seller/login");
 47→      return;
 48→    }
 49→
 50→    let cancelled = false;
 51→
 52→    async function load() {
 53→      try {
 54→        const [stores, locations, plans] = await Promise.all([
 55→          sellerApi.listMyStores(token!),
 56→          sellerApi.listPickupLocations(token!, storeId),
 57→          sellerApi.listSubscriptionPlans(token!, storeId),
 58→        ]);
 59→
 60→        if (cancelled) return;
 61→
 62→        const myStore = stores.find((s) => s.id === storeId) ?? null;
 63→        setStore(myStore);
 64→
 65→        if (locations.length === 0) {
 66→          router.replace(`/seller/stores/${storeId}/setup/location`);
