 14→function parseUSDToCents(raw: string): number | null {
 15→  const v = raw.trim();
 16→  if (!v) return 0;
 17→  const n = Number.parseFloat(v);
 18→  if (!Number.isFinite(n)) return null;
 19→  const cents = Math.round(n * 100);
 20→  if (cents < 0) return null;
 21→  return cents;
 22→}
