 66→export async function generateMetadata({
 67→  params,
 68→}: {
 69→  params: Promise<{ city: string }>;
 70→}): Promise<Metadata> {
 71→  const { city: slug } = await params;
 72→  try {
 73→    const cities = await api.listCities();
 74→    const entry = matchCity(slug, cities);
 75→    if (!entry) return { title: "City — Local Roots" };
 76→
 77→    const title = `Local Farms in ${entry.city}, ${entry.region} — Local Roots`;
 78→    const description = `Browse ${entry.store_count} local farm${entry.store_count !== 1 ? "s" : ""} offering fresh pickup boxes in ${entry.city}, ${entry.region}. Subscribe for weekly farm-fresh food.`;
 79→    return {
 80→      title,
 81→      description,
 82→      openGraph: { title, description, type: "website" },
 83→    };
 84→  } catch {
 85→    return { title: "City — Local Roots" };
 86→  }
